import React, { useState, useEffect } from "react";
import dayjs from "dayjs";
import axios from "axios";
import Cookies from "js-cookie";
import { toast } from "react-toastify";
import { useNavigate } from "react-router-dom";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: { display: false, drawBorder: false },
  ticks: { font: { size: 11 } },
};

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function Dashboard() {
  const navigate = useNavigate();
  const currentYear = new Date().getFullYear();

  const [summaryCards, setSummaryCards] = useState({
    totalUsers: 0,
    totalClient: 0,
    totalRevenue: 0,
    totalSupportTickets: 0,
  });

  const [leadsData, setLeadsData] = useState({});
  const [paymentsData, setPaymentsData] = useState({});

  const [leadYear, setLeadYear] = useState(currentYear);
  const [paymentsYear, setPaymentsYear] = useState(currentYear);
  const [selectedMonth, setSelectedMonth] = useState("all");

  /* ================= FETCH API DATA ================= */
  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) {
      navigate("/");
      return;
    }

    // Fetch users and aggregate leads
    const fetchUsers = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/users`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data.success) {
          setSummaryCards((prev) => ({
            ...prev,
            totalUsers: res.data.totalUsers,
            totalClient: res.data.totalClients,
          }));

          // Aggregate leads by year/month
          const leadAgg = {};
          res.data.data.forEach((user) => {
            const month = dayjs(user.createdAt).month() + 1;
            const year = dayjs(user.createdAt).year();

            if (!leadAgg[year]) leadAgg[year] = {};
            if (!leadAgg[year][month])
              leadAgg[year][month] = { leads: 0, approved: 0, duplicate: 0 };

            leadAgg[year][month].leads += 1;
            if (user.isConverted) leadAgg[year][month].approved += 1;
            if (user.status === "Duplicate") leadAgg[year][month].duplicate += 1;
          });
          setLeadsData(leadAgg);
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching users");
      } finally {
        fetchPayments();
      }
    };

    // Fetch payments
    const fetchPayments = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/payments`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data.success) {
          const paymentAgg = {};
          res.data.data.forEach((p) => {
            const month = dayjs(p.paymentDate).month() + 1;
            const year = dayjs(p.paymentDate).year();

            if (!paymentAgg[year]) paymentAgg[year] = {};
            if (!paymentAgg[year][month])
              paymentAgg[year][month] = { clients: 0, payments: 0 };

            paymentAgg[year][month].clients += 1;
            paymentAgg[year][month].payments += Number(p.paidAmount || 0);
          });

          setPaymentsData(paymentAgg);
          setSummaryCards((prev) => ({
            ...prev,
            totalRevenue: res.data.totalPaidAmount || 0,
          }));

          fetchSupports();
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching payments");
      }
    };

    // Fetch supports for summary card
    const fetchSupports = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/supports`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data.success) {
          setSummaryCards((prev) => ({
            ...prev,
            totalSupportTickets: res.data.totalPendingCount || 0,
          }));
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching supports");
      }
    };

    fetchUsers();
  }, [navigate]);

  /* ================= LEAD CHART DATA ================= */
  const leadYearData = leadsData[leadYear] || {};
  const leadMonths = Object.keys(leadYearData).sort((a, b) => a - b);
  const leadLabels = leadMonths.map((m) =>
    dayjs(`${leadYear}-${m}-01`).format("MMM")
  );
  const leadStatusData = {
    labels: leadLabels,
    datasets: [
      {
        label: "Total Leads",
        data: leadMonths.map((m) => leadYearData[m].leads),
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved Leads",
        data: leadMonths.map((m) => leadYearData[m].approved),
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate Leads",
        data: leadMonths.map((m) => leadYearData[m].duplicate),
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };
  const leadStatusOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: { x: { ...commonGrid }, y: { beginAtZero: true, ...commonGrid } },
  };
  const goToPreviousLeadYear = () => setLeadYear((prev) => prev - 1);
  const goToNextLeadYear = () => setLeadYear((prev) => prev + 1);

  /* ================= PAYMENTS CHART DATA ================= */
  const paymentsYearData = paymentsData[paymentsYear] || {};
  const paymentMonths = Object.keys(paymentsYearData).sort((a, b) => a - b);
  const filteredPaymentMonths =
    selectedMonth === "all"
      ? paymentMonths
      : paymentMonths.filter((m) => m === selectedMonth);
  const paymentLabels = filteredPaymentMonths.map((m) =>
    selectedMonth === "all"
      ? dayjs(`${paymentsYear}-${m}-01`).format("MMM YYYY")
      : dayjs(`${paymentsYear}-${m}-01`).format("DD MMM")
  );

  const clientData = filteredPaymentMonths.map(
    (m) => paymentsYearData[m].clients
  );
  const paymentData = filteredPaymentMonths.map(
    (m) => paymentsYearData[m].payments
  );

  // Example commission: 10% (can be dynamic)
  const commissionData = paymentData.map((amt) =>
    Number(((amt * 10) / 100).toFixed(0))
  );

  const mergedChartData = {
    labels: paymentLabels,
    datasets: [
      {
        label: "Clients Converted",
        data: clientData,
        backgroundColor: "#0d6efd65",
        yAxisID: "yClients",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
    ],
  };

  const mergedChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { ...commonGrid },
      yClients: { type: "linear", position: "left", beginAtZero: true, ...commonGrid },
      yAmount: {
        type: "linear",
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
        ticks: {
          callback: (v) =>
            v < 100000 ? `₹${(v / 1000).toFixed(0)}k` : `₹${(v / 100000).toFixed(0)}L`,
        },
      },
    },
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <div className="row">
        <div className="col-md-12 col-12">
          <h4 className="fw-bold fs-3">Welcome, Admin</h4>
        </div>
        <div className="col-md-12 col-12 pt-2">
          <small>
            Last Updated: {dayjs(new Date()).format("DD MMM YYYY, hh:mm A")}
          </small>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="row g-3 pt-1">
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-25">
            <small><i className="fas fa-users"></i> Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-success border-opacity-25">
            <small><i className="fas fa-user-plus"></i> Total Clients</small>
            <h5>{summaryCards.totalClient}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-warning border-opacity-25">
            <small><i className="fas fa-indian-rupee-sign"></i> Total Revenue</small>
            <h5>{summaryCards.totalRevenue.toLocaleString("en-IN")}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-danger border-opacity-25">
            <small><i className="fas fa-headset"></i> Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      <div className="row pt-3 g-3">
        {/* Lead Chart */}
        <div className="col-lg-6 col-12">
          <div className="border rounded p-3 bg-body h-100 d-flex flex-column">
            <div className="d-flex justify-content-between align-items-center mb-2">
              <h6 className="fw-bold mb-0"><i className="fas fa-chart-column"></i> Leads ({leadYear})</h6>
              <div>
                <button className="btn btn-outline-secondary border-0 btn-sm" onClick={goToPreviousLeadYear}><i className="fas fa-chevron-left"></i></button>
                <button className="btn btn-outline-secondary border-0 btn-sm ms-1" onClick={goToNextLeadYear}><i className="fas fa-chevron-right"></i></button>
              </div>
            </div>
            <div style={{ flex: 1, minHeight: "300px" }}>
              <Bar data={leadStatusData} options={leadStatusOptions} />
            </div>
          </div>
        </div>

        {/* Payments Chart */}
        <div className="col-lg-6 col-12">
          <div className="border rounded p-3 bg-body h-100 d-flex flex-column">
            <div className="row g-3 align-items-center mb-2">
              <div className="col-lg-6 col-12">
                <h6 className="fw-bold mb-0"><i className="fas fa-money-bill-trend-up"></i> Payments Overview ({paymentsYear})</h6>
              </div>
              <div className="col-lg-6 col-12">
                <div className="row g-2">
                  <div className="col-6">
                    <select className="form-select form-select-sm" value={paymentsYear} onChange={(e) => setPaymentsYear(Number(e.target.value))}>
                      {Object.keys(paymentsData).map((year) => (
                        <option key={year} value={year}>{year}</option>
                      ))}
                    </select>
                  </div>
                  <div className="col-6">
                    <select className="form-select form-select-sm" value={selectedMonth} onChange={(e) => setSelectedMonth(e.target.value)}>
                      <option value="all">All Months</option>
                      {paymentMonths.map((month) => (
                        <option key={month} value={month}>{dayjs(`${paymentsYear}-${month}-01`).format("MMM")}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
            </div>
            <div style={{ flex: 1, minHeight: "300px" }}>
              {paymentLabels.length ? <Bar data={mergedChartData} options={mergedChartOptions} /> : (
                <div className="d-flex justify-content-center align-items-center h-100 text-muted">
                  No data available
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
